class PaymentSecurityUtils {
  static String idempotencyKey({
    required String customerId,
    required int amountMinor,
    required String currency,
    required String reference,
  }) {
    final raw =
        '$customerId|$amountMinor|${currency.toUpperCase()}|$reference|${DateTime.now().millisecondsSinceEpoch}';
    return sha256.convert(utf8.encode(raw)).toString();
  }

  static String requestSignature({
    required String payload,
    required String secret,
  }) {
    final hmacSha256 = Hmac(sha256, utf8.encode(secret));
    return hmacSha256.convert(utf8.encode(payload)).toString();
  }

  static bool constantTimeEquals(String a, String b) {
    if (a.length != b.length) return false;
    var result = 0;
    for (var i = 0; i < a.length; i++) {
      result |= a.codeUnitAt(i) ^ b.codeUnitAt(i);
    }
    return result == 0;
  }

  static void assertSecureConfiguration(PaymentModuleConfig config) {
    if (config.apiKey.isEmpty) {
      throw const PaymentException(
        'invalid_config',
        'API key must not be empty',
      );
    }
    if (config.backendBaseUrl.scheme != 'https') {
      throw const PaymentException(
        'insecure_transport',
        'Backend base URL must use HTTPS',
      );
    }
  }
}

