class PaymentApiClient {
  final PaymentModuleConfig config;
  final http.Client _client;

  PaymentApiClient({
    required this.config,
    http.Client? client,
  }) : _client = client ?? http.Client();

  Map<String, String> _headers({
    String? idempotencyKey,
    String? body,
  }) {
    final headers = <String, String>{
      HttpHeaders.contentTypeHeader: 'application/json',
      HttpHeaders.acceptHeader: 'application/json',
      'X-API-Key': config.apiKey,
      'X-Platform': Platform.isIOS ? 'ios' : 'android',
      'X-App-Environment': config.environment.name,
    };
    if (idempotencyKey != null) {
      headers['Idempotency-Key'] = idempotencyKey;
    }
    if (config.enableServerSignatureValidation && body != null) {
      headers['X-Request-Signature'] = PaymentSecurityUtils.requestSignature(
        payload: body,
        secret: config.apiKey,
      );
    }
    return headers;
  }

  Future<Map<String, dynamic>> post(
    String path, {
    required Map<String, dynamic> body,
    String? idempotencyKey,
  }) async {
    final payload = jsonEncode(body);
    final response = await _client
        .post(
          config.backendBaseUrl.resolve(path),
          headers: _headers(idempotencyKey: idempotencyKey, body: payload),
          body: payload,
        )
        .timeout(config.networkTimeout);
    return _parseResponse(response);
  }

  Future<Map<String, dynamic>> get(String path) async {
    final response = await _client
        .get(
          config.backendBaseUrl.resolve(path),
          headers: _headers(),
        )
        .timeout(config.networkTimeout);
    return _parseResponse(response);
  }

  Future<Map<String, dynamic>> _parseResponse(http.Response response) async {
    final body = response.body.isEmpty ? '{}' : response.body;
    final decoded = jsonDecode(body) as Map<String, dynamic>;
    if (response.statusCode < 200 || response.statusCode >= 300) {
      throw PaymentException(
        decoded['code']?.toString() ?? 'api_error',
        decoded['message']?.toString() ?? 'Payment API request failed',
      );
    }
    return decoded;
  }

  void dispose() => _client.close();
}

class InAppPurchaseService {
  final PaymentModuleConfig config;
  final InAppPurchase _iap;
  StreamSubscription<List<PurchaseDetails>>? _subscription;
  final StreamController<PaymentTransaction> _purchaseController =
      StreamController<PaymentTransaction>.broadcast();

  InAppPurchaseService({
    required this.config,
    InAppPurchase? inAppPurchase,
  }) : _iap = inAppPurchase ?? InAppPurchase.instance;

  Stream<PaymentTransaction> get purchaseUpdates => _purchaseController.stream;

  Future<bool> isAvailable() => _iap.isAvailable();

  Future<ProductDetailsResponse> queryProducts() {
    final ids = <String>{
      ...config.consumableProductIds,
      ...config.nonConsumableProductIds,
      ...config.subscriptionProductIds,
    };
    return _iap.queryProductDetails(ids);
  }

  Future<void> initialize({
    required Future<bool> Function(PurchaseDetails purchase) onValidateReceipt,
  }) async {
    _subscription?.cancel();
    _subscription = _iap.purchaseStream.listen(
      (purchases) async {
        for (final purchase in purchases) {
          try {
            final valid = config.enableReceiptValidation
                ? await onValidateReceipt(purchase)
                : true;

            final transaction = PaymentTransaction(
              id: purchase.purchaseID ?? purchase.verificationData.serverVerificationData.hashCode.toString(),
              reference: purchase.productID,
              amountMinor: 0,
              currency: '',
              status: _mapPurchaseStatus(
                purchase.status,
                valid: valid,
                error: purchase.error?.message,
              ),
              methodType: PaymentMethodType.inAppPurchase,
              createdAt: DateTime.now(),
              updatedAt: DateTime.now(),
              gatewayReference: purchase.purchaseID,
              receiptData: purchase.verificationData.serverVerificationData,
              failureCode: purchase.error?.code,
              failureMessage: purchase.error?.message,
              metadata: {
                'productId': purchase.productID,
                'source': 'in_app_purchase',
              },
            );

            _purchaseController.add(transaction);

            if (purchase.pendingCompletePurchase) {
              await _iap.completePurchase(purchase);
            }
          } catch (e, st) {
            _purchaseController.addError(
              PaymentException(
                'purchase_processing_error',
                'Failed to process purchase update',
                cause: e,
                stackTrace: st,
              ),
            );
          }
        }
      },
      onError: (e, st) {
        _purchaseController.addError(
          PaymentException(
            'purchase_stream_error',
            'Purchase stream failed',
            cause: e,
            stackTrace: st,
          ),
        );
      },
    );
  }

  TransactionStatus _mapPurchaseStatus(
    PurchaseStatus status, {
    required bool valid,
    String? error,
  }) {
    switch (status) {
      case PurchaseStatus.pending:
        return TransactionStatus.pending;
      case PurchaseStatus.purchased:
      case PurchaseStatus.restored:
        return valid ? TransactionStatus.succeeded : TransactionStatus.failed;
      case PurchaseStatus.error:
        return error == null
            ? TransactionStatus.failed
            : TransactionStatus.failed;
      case PurchaseStatus.canceled:
        return TransactionStatus.canceled;
    }
  }

  Future<void> buyProduct(ProductDetails product, {required bool consumable}) async {
    final param = PurchaseParam(productDetails: product);
    if (consumable) {
      await _iap.buyConsumable(purchaseParam: param);
    } else {
      await _iap.buyNonConsumable(purchaseParam: param);
    }
  }

  Future<void> restorePurchases() => _iap.restorePurchases();

  Future<void> dispose() async {
    await _subscription?.cancel();
    await _purchaseController.close();
  }
}

class MobileWalletService {
  final PaymentApiClient apiClient;

  MobileWalletService({required this.apiClient});

  Future<bool> isWalletSupported(WalletProvider provider) async {
    if (provider == WalletProvider.applePay) {
      return Platform.isIOS;
    }
    if (provider == WalletProvider.googlePay) {
      return Platform.isAndroid;
    }
    return false;
  }

  Future<PaymentResult> tokenizeAndProcessWalletPayment(
    WalletPaymentRequest request,
  ) async {
    final supported = await isWalletSupported(request.provider);
    if (!supported) {
      throw PaymentException(
        'wallet_not_supported',
        '${request.provider.name} is not supported on this device',
      );
    }

    final walletToken = await _requestWalletToken(request);

    final paymentRequest = PaymentRequest(
      amountMinor: request.amountMinor,
      currency: request.currency,
      customerId: request.customerId,
      reference: request.reference,
      methodType: request.provider == WalletProvider.applePay
          ? PaymentMethodType.applePay
          : PaymentMethodType.googlePay,
      walletToken: walletToken,
      metadata: {
        ...request.metadata,
        'countryCode': request.countryCode,
        'provider': request.provider.name,
      },
    );

    return PaymentProcessor(apiClient: apiClient).processPayment(paymentRequest);
  }

  Future<String> _requestWalletToken(WalletPaymentRequest request) async {
    final seed = jsonEncode({
      'provider': request.provider.name,
      'amountMinor': request.amountMinor,
      'currency': request.currency,
      'customerId': request.customerId,
      'reference': request.reference,
      'timestamp': DateTime.now().toIso8601String(),
    });
    return base64Encode(utf8.encode(seed));
  }
}

class PaymentProcessor {
  final PaymentApiClient apiClient;

  PaymentProcessor({required this.apiClient});

  Future<PaymentResult> processPayment(PaymentRequest request) async {
    _validatePaymentRequest(request);

    final idemKey = PaymentSecurityUtils.idempotencyKey(
      customerId: request.customerId,
      amountMinor: request.amountMinor,
      currency: request.currency,
      reference: request.reference,
    );

    final response = await apiClient.post(
      '/payments/process',
      body: request.toJson(),
      idempotencyKey: idemKey,
    );

    final transaction = PaymentTransaction.fromJson(
      (response['transaction'] as Map).cast<String, dynamic>(),
    );

    return PaymentResult(
      success: transaction.status == TransactionStatus.succeeded,
      transaction: transaction,
      message: response['message']?.toString(),
    );
  }

  Future<PaymentTransaction> capturePayment({
    required String transactionId,
    required int amountMinor,
  }) async {
    final response = await apiClient.post(
      '/payments/$transactionId/capture',
      body: {'amountMinor': amountMinor},
      idempotencyKey: sha256.convert(utf8.encode('$transactionId|$amountMinor')).toString(),
    );
    return PaymentTransaction.fromJson(
      (response['transaction'] as Map).cast<String, dynamic>(),
    );
  }

  Future<PaymentTransaction> refundPayment({
    required String transactionId,
    required int amountMinor,
    String? reason,
  }) async {
    final response = await apiClient.post(
      '/payments/$transactionId/refund',
      body: {
        'amountMinor': amountMinor,
        'reason': reason,
      },
      idempotencyKey: sha256
          .convert(utf8.encode('$transactionId|$amountMinor|${reason ?? ''}'))
          .toString(),
    );
    return PaymentTransaction.fromJson(
      (response['transaction'] as Map).cast<String, dynamic>(),
    );
  }

  Future<PaymentTransaction> getTransaction(String transactionId) async {
    final response = await apiClient.get('/payments/$transactionId');
    return PaymentTransaction.fromJson(
      (response['transaction'] as Map).cast<String, dynamic>(),
    );
  }

  void _validatePaymentRequest(PaymentRequest request) {
    if (request.amountMinor <= 0 &&
        request.methodType != PaymentMethodType.inAppPurchase) {
      throw const PaymentException(
        'invalid_amount',
        'Amount must be greater than zero',
      );
    }
    if (request.currency.trim().isEmpty &&
        request.methodType != PaymentMethodType.inAppPurchase) {
      throw const PaymentException(
        'invalid_currency',
        'Currency is required',
      );
    }
    if (request.customerId.trim().isEmpty) {
      throw const PaymentException(
        'invalid_customer',
        'Customer ID is required',
      );
    }
    if (request.reference.trim().isEmpty) {
      throw const PaymentException(
        'invalid_reference',
        'Reference is required',
      );
    }
    if ((request.methodType == PaymentMethodType.applePay ||
            request.methodType == PaymentMethodType.googlePay) &&
        (request.walletToken == null || request.walletToken!.isEmpty)) {
      throw const PaymentException(
        'missing_wallet_token',
        'Wallet token is required for mobile wallet payments',
      );
    }
    if (request.methodType == PaymentMethodType.cardTokenized &&
        (request.cardToken == null || request.cardToken!.isEmpty)) {
      throw const PaymentException(
        'missing_card_token',
        'Card token is required',
      );
    }
  }
}

class PCIComplianceGuard {
  static void assertNoRawCardData(Map<String, dynamic> payload) {
    const blockedFields = {
      'cardNumber',
      'pan',
      'cvv',
      'cvc',
      'expiry',
      'expMonth',
      'expYear',
      'trackData',
      'pin',
    };

    void scan(dynamic value, [String? key]) {
      if (key != null && blockedFields.contains(key)) {
        throw PaymentException(
          'pci_violation',
          'Raw cardholder data detected in payload for key: $key',
        );
      }
      if (value is Map<String, dynamic>) {
        value.forEach(scan);
      } else if (value is Map) {
        value.forEach((k, v) => scan(v, k.toString()));
      } else if (value is List) {
        for (final item in value) {
          scan(item);
        }
      }
    }

    scan(payload);
  }

  static Map<String, dynamic> sanitizeMetadata(Map<String, dynamic> metadata) {
    final sanitized = <String, dynamic>{};
    metadata.forEach((key, value) {
      final lower = key.toLowerCase();
      if (lower.contains('card') ||
          lower.contains('cvv') ||
          lower.contains('pan') ||
          lower.contains('expiry')) {
        sanitized[key] = '[REDACTED]';
      } else {
        sanitized[key] = value;
      }
    });
    return sanitized;
  }
}

class PaymentModule {
  final PaymentModuleConfig config;
  late final PaymentApiClient apiClient;
  late final PaymentProcessor processor;
  late final InAppPurchaseService inAppPurchaseService;
  late final MobileWalletService walletService;

  PaymentModule._(this.config) {
    apiClient = PaymentApiClient(config: config);
    processor = PaymentProcessor(apiClient: apiClient);
    inAppPurchaseService = InAppPurchaseService(config: config);
    walletService = MobileWalletService(apiClient: apiClient);
  }

  static Future<PaymentModule> initialize(
    PaymentModuleConfig config, {
    Future<bool> Function(PurchaseDetails purchase)? onValidateReceipt,
  }) async {
    PaymentSecurityUtils.assertSecureConfiguration(config);

    final module = PaymentModule._(config);

    if (onValidateReceipt != null) {
      await module.inAppPurchaseService.initialize(
        onValidateReceipt: onValidateReceipt,
      );
    }

    return module;
  }

  Future<PaymentResult> processTokenizedCardPayment({
    required int amountMinor,
    required String currency,
    required String customerId,
    required String reference,
    required String cardToken,
    Map<String, dynamic> metadata = const {},
  }) async {
    PCIComplianceGuard.assertNoRawCardData(metadata);

    final request = PaymentRequest(
      amountMinor: amountMinor,
      currency: currency,
      customerId: customerId,
      reference: reference,
      methodType: PaymentMethodType.cardTokenized,
      cardToken: cardToken,
      metadata: PCIComplianceGuard.sanitizeMetadata(metadata),
    );

    return processor.processPayment(request);
  }

  Future<PaymentResult> processWalletPayment(
    WalletPaymentRequest request,
  ) async {
    PCIComplianceGuard.assertNoRawCardData(request.metadata);
    final sanitizedRequest = WalletPaymentRequest(
      provider: request.provider,
      amountMinor: request.amountMinor,
      currency: request.currency,
      countryCode: request.countryCode,
      customerId: request.customerId,
      reference: request.reference,
      billingContact: request.billingContact,
      shippingContact: request.shippingContact,
      metadata: PCIComplianceGuard.sanitizeMetadata(request.metadata),
    );
    return walletService.tokenizeAndProcessWalletPayment(sanitizedRequest);
  }

  Future<void> dispose() async {
    await inAppPurchaseService.dispose();
    apiClient.dispose();
  }
}

class ExamplePaymentGatewayAdapter {
  final PaymentModule module;

  ExamplePaymentGatewayAdapter(this.module);

  Future<PaymentResult> chargeOrder({
    required String customerId,
    required String orderId,
    required int amountMinor,
    required String currency,
    required String paymentToken,
    bool useWallet = false,
    WalletProvider? walletProvider,
  }) async {
    if (useWallet) {
      return module.processWalletPayment(
        WalletPaymentRequest(
          provider: walletProvider ??
              (Platform.isIOS ? WalletProvider.applePay : WalletProvider.googlePay),
          amountMinor: amountMinor,
          currency: currency,
          countryCode: 'US',
          customerId: customerId,
          reference: orderId,
          metadata: {
            'orderId': orderId,
            'launchMode': 'rapid_deployment',
          },
        ),
      );
    }

    return module.processTokenizedCardPayment(
      amountMinor: amountMinor,
      currency: currency,
      customerId: customerId,
      reference: orderId,
      cardToken: paymentToken,
      metadata: {
        'orderId': orderId,
        'launchMode': 'rapid_deployment',
      },
    );
  }
}